import{_ as a,o as t,c as o,a3 as i}from"./chunks/framework.aYYe0dfI.js";const m=JSON.parse('{"title":"Module extract:compiler","description":"The extract:compiler module is responsible for managing and processing compilation-related data during the extraction pipeline. Its core public data structures, CompileEntry and CompilationDatabase, represent an individual translation unit’s compilation parameters and the overall set of entries loaded from a compilation database, respectively. The module owns a set of public functions that load a compilation database (load_compdb), look up entries by file path (lookup), normalize file paths and arguments (normalize_entry_file, normalize_argument_path), sanitize driver and tool arguments (sanitize_driver_arguments, sanitize_tool_arguments), build content-based compile signatures (build_compile_signature), create compiler instances (create_compiler_instance), strip compiler paths (strip_compiler_path), ensure cache keys on entries (ensure_cache_key), and query toolchain information with caching (query_toolchain_cached). Together, these provide a consistent interface for preparing, normalizing, and caching compilation data before further extraction steps.","frontmatter":{"title":"Module extract:compiler","description":"The extract:compiler module is responsible for managing and processing compilation-related data during the extraction pipeline. Its core public data structures, CompileEntry and CompilationDatabase, represent an individual translation unit’s compilation parameters and the overall set of entries loaded from a compilation database, respectively. The module owns a set of public functions that load a compilation database (load_compdb), look up entries by file path (lookup), normalize file paths and arguments (normalize_entry_file, normalize_argument_path), sanitize driver and tool arguments (sanitize_driver_arguments, sanitize_tool_arguments), build content-based compile signatures (build_compile_signature), create compiler instances (create_compiler_instance), strip compiler paths (strip_compiler_path), ensure cache keys on entries (ensure_cache_key), and query toolchain information with caching (query_toolchain_cached). Together, these provide a consistent interface for preparing, normalizing, and caching compilation data before further extraction steps.","layout":"doc","template":"doc"},"headers":[],"relativePath":"clore/modules/extract/compiler.md","filePath":"en/clore/modules/extract/compiler.md"}'),r={name:"clore/modules/extract/compiler.md"};function c(n,e,l,s,d,h){return t(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="module-extract-compiler" tabindex="-1">Module <code>extract:compiler</code> <a class="header-anchor" href="#module-extract-compiler" aria-label="Permalink to &quot;Module `extract:compiler`&quot;">​</a></h1><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><p>The <code>extract:compiler</code> module is responsible for managing and processing compilation-related data during the extraction pipeline. Its core public data structures, <code>CompileEntry</code> and <code>CompilationDatabase</code>, represent an individual translation unit’s compilation parameters and the overall set of entries loaded from a compilation database, respectively. The module owns a set of public functions that load a compilation database (<code>load_compdb</code>), look up entries by file path (<code>lookup</code>), normalize file paths and arguments (<code>normalize_entry_file</code>, <code>normalize_argument_path</code>), sanitize driver and tool arguments (<code>sanitize_driver_arguments</code>, <code>sanitize_tool_arguments</code>), build content-based compile signatures (<code>build_compile_signature</code>), create compiler instances (<code>create_compiler_instance</code>), strip compiler paths (<code>strip_compiler_path</code>), ensure cache keys on entries (<code>ensure_cache_key</code>), and query toolchain information with caching (<code>query_toolchain_cached</code>). Together, these provide a consistent interface for preparing, normalizing, and caching compilation data before further extraction steps.</p><p>Internally, the module implements utility functions for parsing compiler invocations, hashing source files, normalizing entry files, and building cache keys, all of which support the public API. The <code>CompDbError</code> struct encapsulates database-related errors, while the <code>CompilationDatabase</code> maintains a toolchain cache and a list of entries. By depending on the <code>support</code> module for file I/O, path handling, and logging, <code>extract:compiler</code> abstracts away the low-level details of compilation database reading and argument normalization, offering a focused public scope for managing compile entries and their associated compiler instances.</p><h2 id="imports" tabindex="-1">Imports <a class="header-anchor" href="#imports" aria-label="Permalink to &quot;Imports&quot;">​</a></h2><ul><li><code>std</code></li><li><a href="./../support/"><code>support</code></a></li></ul><h2 id="imported-by" tabindex="-1">Imported By <a class="header-anchor" href="#imported-by" aria-label="Permalink to &quot;Imported By&quot;">​</a></h2><ul><li><a href="./ast"><code>extract:ast</code></a></li><li><a href="./cache"><code>extract:cache</code></a></li><li><a href="./scan"><code>extract:scan</code></a></li></ul><h2 id="types" tabindex="-1">Types <a class="header-anchor" href="#types" aria-label="Permalink to &quot;Types&quot;">​</a></h2><h3 id="clore-extract-compdberror" tabindex="-1"><code>clore::extract::CompDbError</code> <a class="header-anchor" href="#clore-extract-compdberror" aria-label="Permalink to &quot;`clore::extract::CompDbError`&quot;">​</a></h3><p>Declaration: <code>extract/compiler.cppm:38</code></p><p>Definition: <code>extract/compiler.cppm:38</code></p><p>Declaration: <a href="./../../namespaces/clore/extract/"><code>Namespace clore::extract</code></a></p><p>The struct <code>clore::extract::CompDbError</code> is implemented as a thin wrapper around a single <code>std::string</code> member named <code>message</code>. There are no user‑defined constructors, destructors, or assignment <code>operator</code>s; the struct relies entirely on the compiler‑generated defaults. The sole invariant is that <code>message</code> holds a human‑readable description of the error. Because the implementation does not add any custom resource management or validation logic, its correctness depends entirely on the invariants of <code>std::string</code> — namely exception‑safe allocation and copy/move semantics. The struct is trivially copyable and movable via the compiler‑provided operations, making it efficient to pass by value in error‑handling paths.</p><h4 id="invariants" tabindex="-1">Invariants <a class="header-anchor" href="#invariants" aria-label="Permalink to &quot;Invariants&quot;">​</a></h4><ul><li>The <code>message</code> member holds a valid <code>std::string</code> (default-constructed or assigned).</li></ul><h4 id="key-members" tabindex="-1">Key Members <a class="header-anchor" href="#key-members" aria-label="Permalink to &quot;Key Members&quot;">​</a></h4><ul><li><code>message</code>: a <code>std::string</code> representing the error description.</li></ul><h4 id="usage-patterns" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Returned as a result type from extraction operations to indicate failure.</li><li>Inspected by callers to retrieve detailed error text.</li></ul><h3 id="clore-extract-compilationdatabase" tabindex="-1"><code>clore::extract::CompilationDatabase</code> <a class="header-anchor" href="#clore-extract-compilationdatabase" aria-label="Permalink to &quot;`clore::extract::CompilationDatabase`&quot;">​</a></h3><p>Declaration: <code>extract/compiler.cppm:31</code></p><p>Definition: <code>extract/compiler.cppm:31</code></p><p>Declaration: <a href="./../../namespaces/clore/extract/"><code>Namespace clore::extract</code></a></p><p>The struct <code>clore::extract::CompilationDatabase</code> is an internal container that aggregates a flat list of <code>CompileEntry</code> objects in <code>entries</code> and maintains a <code>toolchain_cache</code> mapping toolchain identifiers to their resolved argument sequences. The two fields are default-initialised to empty; <code>entries</code> stores all parsed compilation commands while <code>toolchain_cache</code> acts as a memoization table for toolchain-related lookups, preventing redundant re‑computation. The member <code>has_cached_toolchain</code> simply checks whether the cache is non‑empty, providing an efficient way to test if any toolchain data has been populated without examining the cache contents. This design keeps the database self‑contained and allows quick short‑circuit checks during extraction.</p><h4 id="invariants-1" tabindex="-1">Invariants <a class="header-anchor" href="#invariants-1" aria-label="Permalink to &quot;Invariants&quot;">​</a></h4><ul><li>entries may be empty</li><li><code>toolchain_cache</code> maps toolchain identifiers to flag lists</li><li><code>has_cached_toolchain()</code> returns true if <code>toolchain_cache</code> contains any keys</li></ul><h4 id="key-members-1" tabindex="-1">Key Members <a class="header-anchor" href="#key-members-1" aria-label="Permalink to &quot;Key Members&quot;">​</a></h4><ul><li>entries</li><li><code>toolchain_cache</code></li><li><code>has_cached_toolchain</code></li></ul><h4 id="usage-patterns-1" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-1" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Used to store and pass around parsed compilation database data</li><li><code>toolchain_cache</code> can be populated and queried to avoid repeated toolchain resolution</li></ul><h4 id="member-functions" tabindex="-1">Member Functions <a class="header-anchor" href="#member-functions" aria-label="Permalink to &quot;Member Functions&quot;">​</a></h4><h5 id="clore-extract-compilationdatabase-has-cached-toolchain" tabindex="-1"><code>clore::extract::CompilationDatabase::has_cached_toolchain</code> <a class="header-anchor" href="#clore-extract-compilationdatabase-has-cached-toolchain" aria-label="Permalink to &quot;`clore::extract::CompilationDatabase::has_cached_toolchain`&quot;">​</a></h5><p>Declaration: <code>extract/compiler.cppm:35</code></p><p>Definition: <code>extract/compiler.cppm:229</code></p><p>Declaration: <a href="./../../namespaces/clore/extract/"><code>Namespace clore::extract</code></a></p><h6 id="implementation" tabindex="-1">Implementation <a class="header-anchor" href="#implementation" aria-label="Permalink to &quot;Implementation&quot;">​</a></h6><div class="language-cpp vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">cpp</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">auto</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> CompilationDatabase</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">::</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">has_cached_toolchain</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">() </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">const</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> -&gt;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> bool</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    return</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> !</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">toolchain_cache.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">empty</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">();</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><h3 id="clore-extract-compileentry" tabindex="-1"><code>clore::extract::CompileEntry</code> <a class="header-anchor" href="#clore-extract-compileentry" aria-label="Permalink to &quot;`clore::extract::CompileEntry`&quot;">​</a></h3><p>Declaration: <code>extract/compiler.cppm:21</code></p><p>Definition: <code>extract/compiler.cppm:21</code></p><p>Declaration: <a href="./../../namespaces/clore/extract/"><code>Namespace clore::extract</code></a></p><p>The struct <code>clore::extract::CompileEntry</code> aggregates the data describing a single compilation unit extracted from a build system. The fundamental raw inputs are <code>file</code> (the source file path), <code>directory</code> (the working directory), and <code>arguments</code> (the compiler command‑line tokens). The <code>normalized_file</code> member stores a canonicalized version of the source path, while <code>compile_signature</code> is a hash computed from the combination of file, directory, and arguments, serving as an efficient discriminator for duplicate or equivalent compilations. An optional <code>source_hash</code> may hold a content hash of the source file; its presence is not guaranteed. The <code>cache_key</code> string is a derived, deterministic identifier used for caching or result lookup. An invariant of the structure is that once populated, <code>normalized_file</code> and <code>compile_signature</code> remain consistent with the raw fields, and <code>cache_key</code> is uniquely determined by the compilation signature (and possibly the source hash). The struct is an aggregate with all fields default‑initialized, allowing straightforward brace‑initialization and copying.</p><h4 id="invariants-2" tabindex="-1">Invariants <a class="header-anchor" href="#invariants-2" aria-label="Permalink to &quot;Invariants&quot;">​</a></h4><ul><li>All string fields may be empty</li><li><code>compile_signature</code> is zero-initialized if not set</li><li><code>source_hash</code> is <code>std::nullopt</code> if not available</li></ul><h4 id="key-members-2" tabindex="-1">Key Members <a class="header-anchor" href="#key-members-2" aria-label="Permalink to &quot;Key Members&quot;">​</a></h4><ul><li>file</li><li>directory</li><li>arguments</li><li><code>normalized_file</code></li><li><code>compile_signature</code></li><li><code>source_hash</code></li><li><code>cache_key</code></li></ul><h4 id="usage-patterns-2" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-2" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Used to store compilation entries from <code>clore::extract::Extractor</code></li><li>Populated from build system output like <code>compile_commands.json</code></li><li>Accessed by caching and reproducibility systems</li></ul><h2 id="functions" tabindex="-1">Functions <a class="header-anchor" href="#functions" aria-label="Permalink to &quot;Functions&quot;">​</a></h2><h3 id="clore-extract-build-compile-signature" tabindex="-1"><code>clore::extract::build_compile_signature</code> <a class="header-anchor" href="#clore-extract-build-compile-signature" aria-label="Permalink to &quot;`clore::extract::build_compile_signature`&quot;">​</a></h3><p>Declaration: <code>extract/compiler.cppm:58</code></p><p>Definition: <code>extract/compiler.cppm:110</code></p><p>Declaration: <a href="./../../namespaces/clore/extract/"><code>Namespace clore::extract</code></a></p><p>The function first checks whether the <code>CompileEntry</code> already holds a non-zero <code>compile_signature</code> and a non-empty <code>normalized_file</code>; if so, it short‑circuits by returning that cached value. Otherwise, it determines the normalized file path: if <code>entry.normalized_file</code> is empty, it calls <code>clore::extract::normalize_entry_file</code> to compute it; otherwise it reuses the existing one. It then delegates to the anonymous‑namespace helper <code>clore::extract::(anonymous namespace)::build_compile_signature_impl</code>, passing both the entry and the normalized file path, and returns the resulting <code>std::uint64_t</code> signature. This design centralizes the actual signature computation in the private helper while providing a caching layer that avoids redundant work when the signature and normalized file have already been established.</p><h4 id="side-effects" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects" aria-label="Permalink to &quot;Side Effects&quot;">​</a></h4><p>No observable side effects are evident from the extracted code.</p><h4 id="reads-from" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from" aria-label="Permalink to &quot;Reads From&quot;">​</a></h4><ul><li>entry<code>.normalized_file</code></li><li>entry<code>.compile_signature</code></li><li>entry (via <code>normalize_entry_file</code> and <code>build_compile_signature_impl</code>)</li></ul><h4 id="usage-patterns-3" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-3" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>computing a unique hash for compile entries</li><li>caching compile signatures to avoid redundant computation</li></ul><h3 id="clore-extract-create-compiler-instance" tabindex="-1"><code>clore::extract::create_compiler_instance</code> <a class="header-anchor" href="#clore-extract-create-compiler-instance" aria-label="Permalink to &quot;`clore::extract::create_compiler_instance`&quot;">​</a></h3><p>Declaration: <code>extract/compiler.cppm:65</code></p><p>Definition: <code>extract/compiler.cppm:297</code></p><p>Declaration: <a href="./../../namespaces/clore/extract/"><code>Namespace clore::extract</code></a></p><p>The function first sanitizes the command-line arguments via <code>sanitize_driver_arguments</code>; an empty result causes an immediate <code>nullptr</code> return. A physical file system is created, and a diagnostic engine is constructed using <code>clang::CompilerInstance::createDiagnostics</code> with an ignoring consumer. If diagnostics creation fails, the function returns <code>nullptr</code>. The sanitized arguments, together with <code>entry.file</code>, the virtual file system, and the diagnostics, are passed to <code>parse_compiler_invocation</code> to produce a <code>clang::CompilerInvocation</code>. If parsing fails, <code>nullptr</code> is returned. The invocation&#39;s frontend options are adjusted: <code>DisableFree</code> is set to false, and <code>WorkingDir</code> is set to <code>entry.directory</code>. If the invocation has no frontend inputs, the function returns <code>nullptr</code>. Finally, a <code>clang::CompilerInstance</code> is constructed from the invocation, its virtual file system is set, diagnostics are recreated for the instance, a file manager is created, and target creation is attempted. Failure at any of these steps yields <code>nullptr</code>; otherwise, the fully initialized instance is returned. Key dependencies include <code>sanitize_driver_arguments</code>, <code>parse_compiler_invocation</code>, <code>llvm::vfs::FileSystem</code>, <code>clang::DiagnosticsEngine</code>, <code>clang::CompilerInvocation</code>, and <code>clang::CompilerInstance</code>.</p><h4 id="side-effects-1" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects-1" aria-label="Permalink to &quot;Side Effects&quot;">​</a></h4><ul><li>Allocates a <code>clang::CompilerInstance</code> and related objects (VFS, diagnostics, invocation).</li><li>Writes to the diagnostics object via <code>IgnoringDiagConsumer</code> during invocation parsing.</li><li>Potentially performs I/O when parsing the compiler invocation (e.g., reading source files or configuration).</li></ul><h4 id="reads-from-1" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from-1" aria-label="Permalink to &quot;Reads From&quot;">​</a></h4><ul><li><code>entry</code> (the <code>CompileEntry</code> parameter), specifically <code>entry.file</code> and <code>entry.directory</code></li><li><code>driver_args</code> returned from <code>sanitize_driver_arguments(entry)</code></li></ul><h4 id="writes-to" tabindex="-1">Writes To <a class="header-anchor" href="#writes-to" aria-label="Permalink to &quot;Writes To&quot;">​</a></h4><ul><li>The returned <code>std::unique_ptr&lt;clang::CompilerInstance&gt;</code></li><li>Diagnostics object created internally (written by <code>parse_compiler_invocation</code>)</li></ul><h4 id="usage-patterns-4" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-4" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Called in extraction pipeline to obtain a Clang compiler instance for a compilation unit.</li><li>Used as part of the process to analyze source code and extract symbol information.</li></ul><h3 id="clore-extract-ensure-cache-key" tabindex="-1"><code>clore::extract::ensure_cache_key</code> <a class="header-anchor" href="#clore-extract-ensure-cache-key" aria-label="Permalink to &quot;`clore::extract::ensure_cache_key`&quot;">​</a></h3><p>Declaration: <code>extract/compiler.cppm:60</code></p><p>Definition: <code>extract/compiler.cppm:225</code></p><p>Declaration: <a href="./../../namespaces/clore/extract/"><code>Namespace clore::extract</code></a></p><p>Implementation: <a href="./functions/ensure-cache-key">Implementation</a></p><p>The function <code>clore::extract::ensure_cache_key</code> serves as a thin entry point that delegates entirely to the implementation function <code>ensure_cache_key_impl</code>. Its purpose is to separate the public interface from the actual cache-key computation logic, allowing the implementation details—such as argument sanitization, compiler invocation parsing, file normalization, and hash generation—to evolve without affecting callers. The single call to <code>ensure_cache_key_impl</code> handles all internal control flow, including conditional checks for cached toolchain data, error handling for missing or invalid compilation databases, and the final assignment of the <code>CompileEntry::cache_key</code> field.</p><h4 id="side-effects-2" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects-2" aria-label="Permalink to &quot;Side Effects&quot;">​</a></h4><ul><li>modifies the cache key field of the <code>CompileEntry</code></li></ul><h4 id="reads-from-2" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from-2" aria-label="Permalink to &quot;Reads From&quot;">​</a></h4><ul><li>the <code>CompileEntry</code> object (fields may be read to compute the cache key)</li></ul><h4 id="writes-to-1" tabindex="-1">Writes To <a class="header-anchor" href="#writes-to-1" aria-label="Permalink to &quot;Writes To&quot;">​</a></h4><ul><li>the <code>CompileEntry</code> object (specifically the cache key field)</li></ul><h4 id="usage-patterns-5" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-5" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>called by <code>query_toolchain_cached</code> before caching or querying toolchain for a compile entry</li></ul><h3 id="clore-extract-ensure-cache-key-impl" tabindex="-1"><code>clore::extract::ensure_cache_key_impl</code> <a class="header-anchor" href="#clore-extract-ensure-cache-key-impl" aria-label="Permalink to &quot;`clore::extract::ensure_cache_key_impl`&quot;">​</a></h3><p>Declaration: <code>extract/compiler.cppm:119</code></p><p>Definition: <code>extract/compiler.cppm:119</code></p><p>Declaration: <a href="./../../namespaces/clore/extract/"><code>Namespace clore::extract</code></a></p><p>Implementation: <a href="./functions/ensure-cache-key-impl">Implementation</a></p><p>The function <code>clore::extract::ensure_cache_key_impl</code> computes and stores the caching metadata for a given <code>CompileEntry</code>. It begins by obtaining a normalized file path via <code>clore::extract::normalize_entry_file</code>, storing the result into the <code>normalized_file</code> field. Next, it derives a compile signature by calling <code>clore::extract::(anonymous namespace)::build_compile_signature_impl</code> with the entry and the normalized path, saving the result into <code>compile_signature</code>. An optional source file hash is produced by <code>clore::extract::(anonymous namespace)::try_hash_source_file</code> using the normalized file, and that heuristics result is written to <code>source_hash</code>. Finally, the function assembles the <code>cache_key</code> by invoking <code>clore::support::build_cache_key</code> with the normalized file and the compile signature. The control flow is strictly sequential; each step depends on the output of the previous one, and all key values are later used by the caching and lookup mechanisms.</p><h4 id="side-effects-3" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects-3" aria-label="Permalink to &quot;Side Effects&quot;">​</a></h4><ul><li>mutates entry fields: <code>normalized_file</code>, <code>compile_signature</code>, <code>source_hash</code>, <code>cache_key</code></li><li>potentially reads source file via <code>try_hash_source_file</code></li></ul><h4 id="reads-from-3" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from-3" aria-label="Permalink to &quot;Reads From&quot;">​</a></h4><ul><li>entry (<code>CompileEntry</code>&amp; parameter)</li></ul><h4 id="writes-to-2" tabindex="-1">Writes To <a class="header-anchor" href="#writes-to-2" aria-label="Permalink to &quot;Writes To&quot;">​</a></h4><ul><li>entry<code>.normalized_file</code></li><li>entry<code>.compile_signature</code></li><li>entry<code>.source_hash</code></li><li>entry<code>.cache_key</code></li></ul><h4 id="usage-patterns-6" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-6" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>called by <code>ensure_cache_key</code> to populate cache key for a compile entry</li></ul><h3 id="clore-extract-load-compdb" tabindex="-1"><code>clore::extract::load_compdb</code> <a class="header-anchor" href="#clore-extract-load-compdb" aria-label="Permalink to &quot;`clore::extract::load_compdb`&quot;">​</a></h3><p>Declaration: <code>extract/compiler.cppm:42</code></p><p>Definition: <code>extract/compiler.cppm:127</code></p><p>Declaration: <a href="./../../namespaces/clore/extract/"><code>Namespace clore::extract</code></a></p><p>The function <code>clore::extract::load_compdb</code> begins by checking that the given <code>path</code> exists as a filesystem path; if not, it returns an error via <code>CompDbError</code>. It then loads the JSON compilation database using <code>clang::tooling::JSONCompilationDatabase::loadFromFile</code>, passing the raw <code>path</code> and an <code>error_message</code> output parameter. On failure, it returns an error describing the load failure. On success, it iterates over all compile commands from the database. For each command, it constructs a <code>CompileEntry</code>, populating <code>file</code>, <code>directory</code>, and <code>arguments</code> from the command’s <code>Filename</code>, <code>Directory</code>, and <code>CommandLine</code> fields. The helper <code>ensure_cache_key</code> is called on each entry to compute and store a <code>cache_key</code> (which later participates in deduplication and toolchain caching). The entries are moved into <code>CompilationDatabase::entries</code>. Finally, the function logs the number of loaded commands and returns the populated <code>CompilationDatabase</code>. The algorithm depends on <code>std::filesystem</code> for existence checks, <code>clang::tooling::JSONCompilationDatabase</code> for parsing, and internal routines such as <code>ensure_cache_key</code> for key derivation.</p><h4 id="side-effects-4" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects-4" aria-label="Permalink to &quot;Side Effects&quot;">​</a></h4><ul><li>Reads file system to check existence of compilation database file</li><li>Opens and parses JSON compilation database file</li><li>Allocates memory for <code>CompileEntry</code> objects</li><li>Calls <code>ensure_cache_key</code> for each entry, mutating the entry&#39;s internal state</li><li>Logs an informational message with the number of loaded commands</li></ul><h4 id="reads-from-4" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from-4" aria-label="Permalink to &quot;Reads From&quot;">​</a></h4><ul><li>File system via the <code>path</code> parameter</li><li>Contents of the JSON file at <code>path</code></li><li>Global or local <code>logging</code> facility (for <code>logging::info</code>)</li></ul><h4 id="writes-to-3" tabindex="-1">Writes To <a class="header-anchor" href="#writes-to-3" aria-label="Permalink to &quot;Writes To&quot;">​</a></h4><ul><li>Local <code>CompilationDatabase</code> object (<code>db</code>) and its <code>entries</code> vector</li><li>Each <code>CompileEntry</code> within <code>db</code> (mutated by <code>ensure_cache_key</code>)</li><li>Log output (via <code>logging::info</code>)</li></ul><h4 id="usage-patterns-7" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-7" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Loading a compilation database from a path to <code>compile_commands.json</code></li><li>Initializing extraction processes for a project</li><li>Providing compile commands to build dependency graphs or symbol indexes</li></ul><h3 id="clore-extract-lookup" tabindex="-1"><code>clore::extract::lookup</code> <a class="header-anchor" href="#clore-extract-lookup" aria-label="Permalink to &quot;`clore::extract::lookup`&quot;">​</a></h3><p>Declaration: <code>extract/compiler.cppm:44</code></p><p>Definition: <code>extract/compiler.cppm:164</code></p><p>Declaration: <a href="./../../namespaces/clore/extract/"><code>Namespace clore::extract</code></a></p><p>The function <code>clore::extract::lookup</code> iterates over all entries in the provided <code>clore::extract::CompilationDatabase</code> and identifies those whose compiled source file matches the given <code>file</code> path. For each entry, it calls <code>normalize_argument_path</code> to resolve the input <code>file</code> relative to the entry’s <code>directory</code>, producing a canonical absolute path. It then compares this candidate against the entry’s normalized file, which is either pre‑computed in <code>entry.normalized_file</code> or obtained on‑the‑fly via <code>normalize_entry_file</code>. If the two paths are equal (using <code>std::filesystem::path</code> equality), a pointer to the entry is appended to the result vector.</p><p>The algorithm relies entirely on <code>normalize_argument_path</code> and <code>normalize_entry_file</code> for path normalization, and on <code>std::filesystem</code> for path comparison. The function returns a possibly empty <code>std::vector&lt;const CompileEntry*&gt;</code>, allowing callers to handle multiple entries that map to the same source file. No error handling is performed; if no match is found, an empty vector is returned.</p><h4 id="side-effects-5" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects-5" aria-label="Permalink to &quot;Side Effects&quot;">​</a></h4><p>No observable side effects are evident from the extracted code.</p><h4 id="reads-from-5" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from-5" aria-label="Permalink to &quot;Reads From&quot;">​</a></h4><ul><li>db<code>.entries</code></li><li>file (parameter)</li><li>entry<code>.directory</code></li><li>entry<code>.normalized_file</code></li></ul><h4 id="usage-patterns-8" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-8" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Used to find compile entries corresponding to a source file path</li><li>Called during extraction to associate a source file with its build configuration</li></ul><h3 id="clore-extract-normalize-argument-path" tabindex="-1"><code>clore::extract::normalize_argument_path</code> <a class="header-anchor" href="#clore-extract-normalize-argument-path" aria-label="Permalink to &quot;`clore::extract::normalize_argument_path`&quot;">​</a></h3><p>Declaration: <code>extract/compiler.cppm:49</code></p><p>Definition: <code>extract/compiler.cppm:188</code></p><p>Declaration: <a href="./../../namespaces/clore/extract/"><code>Namespace clore::extract</code></a></p><p>The function constructs a normalized filesystem path from a raw <code>path</code> and a <code>directory</code>. It first creates a <code>std::filesystem::path</code> from <code>path</code>, and if it is relative, prepends <code>directory</code> by concatenating <code>std::filesystem::path(directory) / normalized</code>. It then attempts to convert the result to an absolute path via <code>std::filesystem::absolute</code>, capturing any <code>std::error_code</code>; on success, it replaces <code>normalized</code> with the absolute path. After calling <code>normalized.lexically_normal()</code> to remove redundant elements (e.g., <code>..</code> or <code>.</code>), it tries to produce a canonical, symlink‑resolved path using <code>std::filesystem::weakly_canonical</code>. If that operation does not fail, it returns the canonical path; otherwise, it falls back to the lexically‑normalized path. The function relies solely on the C++ standard library’s <code>std::filesystem</code> facilities and does not invoke any other <code>clore::extract</code> routines.</p><h4 id="side-effects-6" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects-6" aria-label="Permalink to &quot;Side Effects&quot;">​</a></h4><p>No observable side effects are evident from the extracted code.</p><h4 id="reads-from-6" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from-6" aria-label="Permalink to &quot;Reads From&quot;">​</a></h4><ul><li><code>path</code> parameter</li><li><code>directory</code> parameter</li><li>filesystem state (via <code>std::filesystem::absolute</code> and <code>std::filesystem::weakly_canonical</code>)</li></ul><h4 id="usage-patterns-9" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-9" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Normalize compiler argument paths for consistent processing</li></ul><h3 id="clore-extract-normalize-entry-file" tabindex="-1"><code>clore::extract::normalize_entry_file</code> <a class="header-anchor" href="#clore-extract-normalize-entry-file" aria-label="Permalink to &quot;`clore::extract::normalize_entry_file`&quot;">​</a></h3><p>Declaration: <code>extract/compiler.cppm:56</code></p><p>Definition: <code>extract/compiler.cppm:91</code></p><p>Declaration: <a href="./../../namespaces/clore/extract/"><code>Namespace clore::extract</code></a></p><p>Implementation: <a href="./functions/normalize-entry-file">Implementation</a></p><p>The function <code>clore::extract::normalize_entry_file</code> takes a <code>CompileEntry</code> and returns a normalized file path as a <code>std::string</code>. It begins by constructing a <code>std::filesystem::path</code> from <code>entry.file</code>. If the path is relative, it is prefixed with <code>entry.directory</code>. After converting to an absolute path using <code>fs::absolute</code> (with error checking), the path is normalized via <code>lexically_normal()</code>. A subsequent call to <code>fs::weakly_canonical</code> attempts to resolve any symbolic links and produce a canonical path; if this fails (e.g., the file does not exist), the function falls back to the lexically-normalized path. The result is always returned as a generic string (forward slashes).</p><p>Internally, the function relies solely on the <code>std::filesystem</code> library and the <code>CompileEntry</code> fields <code>file</code> and <code>directory</code>. Error codes from <code>weakly_canonical</code> are captured but not propagated—the function degrades gracefully to the non-canonical form. This ensures robust behavior when the input file does not exist on disk or when filesystem resolution fails. The algorithm prioritizes accuracy (canonical form when possible) over strict failure reporting.</p><h4 id="side-effects-7" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects-7" aria-label="Permalink to &quot;Side Effects&quot;">​</a></h4><p>No observable side effects are evident from the extracted code.</p><h4 id="reads-from-7" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from-7" aria-label="Permalink to &quot;Reads From&quot;">​</a></h4><ul><li><code>entry.file</code></li><li><code>entry.directory</code></li></ul><h4 id="usage-patterns-10" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-10" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Called by <code>build_compile_signature</code> to derive a unique signature for a compile entry.</li><li>Called by <code>ensure_cache_key_impl</code> to produce a normalized file path for cache key computation.</li></ul><h3 id="clore-extract-query-toolchain-cached" tabindex="-1"><code>clore::extract::query_toolchain_cached</code> <a class="header-anchor" href="#clore-extract-query-toolchain-cached" aria-label="Permalink to &quot;`clore::extract::query_toolchain_cached`&quot;">​</a></h3><p>Declaration: <code>extract/compiler.cppm:62</code></p><p>Definition: <code>extract/compiler.cppm:233</code></p><p>Declaration: <a href="./../../namespaces/clore/extract/"><code>Namespace clore::extract</code></a></p><p>The function first checks if <code>entry.arguments</code> is empty and returns an empty vector if so. It then attempts to obtain a cache key from <code>entry.cache_key</code>; if that field is empty, it creates a copy of the entry and calls <code>ensure_cache_key</code> on the copy to populate its <code>cache_key</code> field, then uses that key for lookup. Using the key, it searches <code>db.toolchain_cache</code>; if a cached value exists, it is returned immediately. Otherwise, the function calls <code>sanitize_tool_arguments</code> on the original entry to produce the toolchain arguments, inserts the result into the cache under the key, and returns the computed vector. This design ensures that each unique compilation entry (as identified by its cache key) triggers the potentially expensive sanitization only once per database session.</p><h4 id="side-effects-8" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects-8" aria-label="Permalink to &quot;Side Effects&quot;">​</a></h4><ul><li>Inserts or updates entries in <code>db.toolchain_cache</code></li></ul><h4 id="reads-from-8" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from-8" aria-label="Permalink to &quot;Reads From&quot;">​</a></h4><ul><li><code>entry.arguments</code></li><li><code>entry.cache_key</code></li><li><code>db.toolchain_cache</code></li></ul><h4 id="writes-to-4" tabindex="-1">Writes To <a class="header-anchor" href="#writes-to-4" aria-label="Permalink to &quot;Writes To&quot;">​</a></h4><ul><li><code>db.toolchain_cache</code></li></ul><h4 id="usage-patterns-11" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-11" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Used to obtain sanitized tool arguments with memoization</li><li>Callers rely on caching to avoid redundant calls to <code>sanitize_tool_arguments</code></li></ul><h3 id="clore-extract-sanitize-driver-arguments" tabindex="-1"><code>clore::extract::sanitize_driver_arguments</code> <a class="header-anchor" href="#clore-extract-sanitize-driver-arguments" aria-label="Permalink to &quot;`clore::extract::sanitize_driver_arguments`&quot;">​</a></h3><p>Declaration: <code>extract/compiler.cppm:52</code></p><p>Definition: <code>extract/compiler.cppm:207</code></p><p>Declaration: <a href="./../../namespaces/clore/extract/"><code>Namespace clore::extract</code></a></p><p>The function <code>clore::extract::sanitize_driver_arguments</code> begins by obtaining a copy of the <code>CompileEntry</code>’s <code>arguments</code> into <code>adjusted</code>. It then normalizes the original input file path by calling <code>normalize_argument_path</code> with <code>entry.file</code> and <code>entry.directory</code>. Using <code>std::erase_if</code>, it scans every argument in <code>adjusted</code>; any non‑empty argument that does not start with a dash (<code>-</code>) is further checked by normalizing it relative to <code>entry.directory</code>. If the normalized result matches the normalized source path, that argument is removed from the vector. The resulting <code>adjusted</code> list, which no longer contains the explicit input file argument, is returned.</p><p>The algorithm relies on <code>normalize_argument_path</code> (defined in the anonymous namespace) to produce a canonical absolute path from a given path and a working directory. It assumes all relevant arguments are already present in the <code>CompileEntry::arguments</code> list and that the input file appears there as a non‑flag argument. No other data structures or global state are modified; the function works purely on local copies and the provided <code>entry</code>.</p><h4 id="side-effects-9" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects-9" aria-label="Permalink to &quot;Side Effects&quot;">​</a></h4><p>No observable side effects are evident from the extracted code.</p><h4 id="reads-from-9" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from-9" aria-label="Permalink to &quot;Reads From&quot;">​</a></h4><ul><li><code>entry.arguments</code></li><li><code>entry.file</code></li><li><code>entry.directory</code></li><li><code>clore::extract::normalize_argument_path</code></li></ul><h4 id="usage-patterns-12" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-12" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>used to remove the source file from compiler arguments</li><li>called before building compile signature or invoking compiler</li></ul><h3 id="clore-extract-sanitize-tool-arguments" tabindex="-1"><code>clore::extract::sanitize_tool_arguments</code> <a class="header-anchor" href="#clore-extract-sanitize-tool-arguments" aria-label="Permalink to &quot;`clore::extract::sanitize_tool_arguments`&quot;">​</a></h3><p>Declaration: <code>extract/compiler.cppm:54</code></p><p>Definition: <code>extract/compiler.cppm:221</code></p><p>Declaration: <a href="./../../namespaces/clore/extract/"><code>Namespace clore::extract</code></a></p><p>The implementation of <code>clore::extract::sanitize_tool_arguments</code> is a direct two‑stage pipeline. It first calls <code>sanitize_driver_arguments</code>, passing the <code>const CompileEntry&amp; entry</code>. That function is responsible for parsing and normalizing the driver‑level arguments stored in the entry’s <code>arguments</code> field. The result from <code>sanitize_driver_arguments</code> is then immediately forwarded to <code>strip_compiler_path</code>, which removes the compiler executable path (the first argument of the invocation) from the argument vector. The final returned value is a <code>std::vector&lt;std::string&gt;</code> containing the remaining, sanitized tool arguments. No branching or further transformation occurs inside <code>sanitize_tool_arguments</code> itself; all logic is delegated to these two dependency functions.</p><h4 id="side-effects-10" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects-10" aria-label="Permalink to &quot;Side Effects&quot;">​</a></h4><p>No observable side effects are evident from the extracted code.</p><h4 id="reads-from-10" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from-10" aria-label="Permalink to &quot;Reads From&quot;">​</a></h4><ul><li>entry</li></ul><h4 id="usage-patterns-13" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-13" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Used when normalizing compile arguments</li><li>Called during extraction pipeline</li></ul><h3 id="clore-extract-strip-compiler-path" tabindex="-1"><code>clore::extract::strip_compiler_path</code> <a class="header-anchor" href="#clore-extract-strip-compiler-path" aria-label="Permalink to &quot;`clore::extract::strip_compiler_path`&quot;">​</a></h3><p>Declaration: <code>extract/compiler.cppm:47</code></p><p>Definition: <code>extract/compiler.cppm:181</code></p><p>Declaration: <a href="./../../namespaces/clore/extract/"><code>Namespace clore::extract</code></a></p><p>The implementation of <code>clore::extract::strip_compiler_path</code> applies a simple truncation algorithm: when the input <code>std::vector&lt;std::string&gt;</code> of arguments contains one or fewer elements, it returns an empty vector. Otherwise, it constructs a new vector containing every element except the first by copying from <code>args.begin() + 1</code> to <code>args.end()</code>. This effectively removes the compiler executable path from a command-line argument list.</p><p>The sole control flow is an early return on <code>args.size() &lt;= 1</code>. The function depends only on the standard library’s <code>std::vector</code>, its <code>size</code> and <code>begin</code> / <code>end</code> iterators, and the iterator-range constructor used for the copy. No external project dependencies are required.</p><h4 id="side-effects-11" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects-11" aria-label="Permalink to &quot;Side Effects&quot;">​</a></h4><p>No observable side effects are evident from the extracted code.</p><h4 id="reads-from-11" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from-11" aria-label="Permalink to &quot;Reads From&quot;">​</a></h4><ul><li><code>args</code> parameter</li></ul><h4 id="writes-to-5" tabindex="-1">Writes To <a class="header-anchor" href="#writes-to-5" aria-label="Permalink to &quot;Writes To&quot;">​</a></h4><ul><li>return value (new vector)</li></ul><h4 id="usage-patterns-14" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-14" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>used to obtain compiler flags without the program name</li></ul><h2 id="internal-structure" tabindex="-1">Internal Structure <a class="header-anchor" href="#internal-structure" aria-label="Permalink to &quot;Internal Structure&quot;">​</a></h2><p>The <code>extract:compiler</code> module is the intermediary between raw compilation database entries and the actual Clang compiler invocations used during extraction. It imports only the <code>std</code> library and the local <code>support</code> module, which supplies foundational utilities for file I/O, path normalization, and cache key management. The module decomposes into three layers: data structures (<code>CompileEntry</code>, <code>CompilationDatabase</code>, <code>CompDbError</code>), public API functions, and private helpers in an anonymous namespace. Public functions like <code>load_compdb</code>, <code>lookup</code>, and <code>sanitize_driver_arguments</code> operate on the database and entries, while private helpers such as <code>parse_compiler_invocation</code>, <code>try_hash_source_file</code>, and <code>build_compile_signature_impl</code> handle path resolution, argument stripping, signature hashing, and compiler instance creation. This layering ensures that caching and normalization logic is encapsulated, leaving the public API stable and focused on extracting ready‑to‑use compiler invocations from concrete compile entries.</p><h2 id="related-pages" tabindex="-1">Related Pages <a class="header-anchor" href="#related-pages" aria-label="Permalink to &quot;Related Pages&quot;">​</a></h2><ul><li><a href="./../support/">Module support</a></li></ul>',205)])])}const u=a(r,[["render",c]]);export{m as __pageData,u as default};
